import{L as e,W as t,b as n,d as r,m as i,rt as a,t as o,v as s,y as c}from"./chunks/plugin-vue_export-helper.D3GSJjLW.js";const l=JSON.parse(`{"title":"Manga Image Editing","description":"","frontmatter":{"title":"Manga Image Editing","customDescription":"Image Magick guide for Grayscaling, Leveling, and Optimizing","outline":[2,3],"og":{"image":"https://i.wotaku.wiki/f/guide.png"}},"headers":[],"relativePath":"guides/manga/imagedit.md","filePath":"guides/manga/imagedit.md","lastUpdated":1781705659000}`);var u={name:`guides/manga/imagedit.md`},d={id:`simple-denoising`,tabindex:`-1`},f={class:`info custom-block`},p={id:`grayscaling`,tabindex:`-1`},m={id:`leveling`,tabindex:`-1`},h={id:`optimizing`,tabindex:`-1`};function g(o,l,u,g,_,v){let y=t(`NolebasePageProperties`),b=t(`Authors`),x=t(`Feedback`),S=t(`tooltip`);return e(),i(`div`,null,[n(y),l[15]||=r(`p`,null,`A simple to understand guide covering the most important page edits.`,-1),n(b,{page:`imagedit`}),r(`h2`,d,[l[0]||=c(`Simple Denoising `,-1),n(x,{heading:`Simple Denoising`}),l[1]||=r(`a`,{class:`header-anchor`,href:`#simple-denoising`,"aria-label":`Permalink to “Simple Denoising”`},`​`,-1)]),l[16]||=s(`<p>One can simple denoise pages using Waifu2x, which, contrary to its primary function, is not only used for upscaling. For Windows, you could use <a href="https://github.com/lltcggie/waifu2x-caffe/releases" target="_blank" rel="noreferrer"><strong>waifu2x-caffe</strong></a>, which has a GUI, but is limited to NVIDIA GPUs. Having a reasonably fast GPU is highly recommended (for reference: a GTX 1650 will perform well, while a GT 730 will struggle). Of course, you can denoise in CPU mode, but it will be much slower.</p><p>Using the <code>2-D Illust (CUnet Model)</code> on <code>Level 2 Denoise Only</code> and <code>Use TTA Mode</code> unchecked is generally &quot;good enough&quot; for denoising on low to mid-range machines. Keep in mind that the denoise level depends on JPEG quality. There&#39;s no hard rule, but generally, for a q92 image, level 0 should be enough, whereas a q70 image would probably require level 2.</p><figure><img src="/open-source-software/ss/waifu.jpg" alt="generic denoising" tabindex="0" loading="lazy"><figcaption>generic denoising</figcaption></figure><p>Under processing Speed Settings, it is recommended to leave the split size on default unless you are getting weird/incorrect outputs, in which case you might need to adjust it. You can increase the batch size if your GPU can handle more load to process the splits in parallel to speed up the denoising.</p><p>The <code>Use TTA Mode</code> will process each split piece multiple times, rotating around (8 rotations in total). This generally improves the denoising, but the total processing will take 8 times longer, so for simple, fast, good-enough denoising, you can leave it unchecked unless you have the time for it.</p><p>On a final note, it is recommended to set the output extension to PNG, as this is a lossless file format, unlike JPEG, which would reintroduce artifacts that you just took the effort to denoise.</p><p>And last but not least: if you have a reasonably fast AMD GPU, consider using other Waifu2x implementations like <a href="https://github.com/YukihoAA/waifu2x_snowshell" target="_blank" rel="noreferrer"><strong>waifu2x-snowshell</strong></a>, as Waifu2x-Caffe only supports NVIDIA.</p>`,7),r(`div`,f,[l[7]||=r(`p`,{class:`custom-block-title`},`Tools Needed`,-1),l[8]||=r(`p`,null,`The following tools will be used for any kind of grayscaling, leveling, and lossless optimizing:`,-1),r(`ul`,null,[l[5]||=r(`li`,null,[r(`a`,{href:`https://imagemagick.org/index.php`,target:`_blank`,rel:`noreferrer`},`ImageMagick`)],-1),l[6]||=r(`li`,null,[r(`a`,{href:`https://css-ig.net/pingo`,target:`_blank`,rel:`noreferrer`},`Pingo`)],-1),r(`li`,null,[l[3]||=r(`a`,{href:`https://github.com/DrWhoCares/imgdanke`,target:`_blank`,rel:`noreferrer`},`imgdanke`,-1),l[4]||=c(),n(S,null,{default:a(()=>[...l[2]||=[c(`Optional for GUI but does not support Pingo version 1+ at the moment.`,-1)]]),_:1})])])]),r(`h2`,p,[l[9]||=c(`Grayscaling `,-1),n(x,{heading:`Grayscaling`}),l[10]||=r(`a`,{class:`header-anchor`,href:`#grayscaling`,"aria-label":`Permalink to “Grayscaling”`},`​`,-1)]),l[17]||=s(`<p>The majority of the panels are black and white and can safely be grayscaled if they aren&#39;t already (e.g., 24-bit JPEGs or PNGs) to reduce the file size of those images.</p><p>The command (CLI) to use with ImageMagick to batch process all images inside the current folder (that your command prompt is in) would be:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>magick mogrify -format png -dither None -colorspace Gray *.png</span></span></code></pre></div>`,3),r(`h2`,m,[l[11]||=c(`Leveling `,-1),n(x,{heading:`Leveling`}),l[12]||=r(`a`,{class:`header-anchor`,href:`#leveling`,"aria-label":`Permalink to “Leveling”`},`​`,-1)]),l[18]||=s(`<p>Leveling images is required when blacks aren&#39;t actually black, and after grayscaling, they may look a bit washed out. Before grayscaling, images can even have a hue or colored tint.</p><figure><img src="/open-source-software/ss/scaling.png" alt="leveling example" tabindex="0" loading="lazy"><figcaption>leveling example</figcaption></figure><h3 id="stretching" tabindex="-1">Stretching <a class="header-anchor" href="#stretching" aria-label="Permalink to “Stretching”">​</a></h3><p>A simple method without too much effort would be using the <code>-contrast-stretch</code> option from ImageMagick, which will try to stretch the closest blacks to #000 and the highest whites to #fff. However, this does not work properly if there are pixels closer to black than the intended targeted blacks, as the stretch finds the lowest/highest colors.</p><p>The command (CLI) to use with ImageMagick to batch process all images inside a folder would be:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>magick mogrify -format png -dither None -colorspace Gray -contrast-stretch 0%x0% *.png</span></span></code></pre></div><h3 id="manual-leveling" tabindex="-1">Manual Leveling <a class="header-anchor" href="#manual-leveling" aria-label="Permalink to “Manual Leveling”">​</a></h3><p>With manual leveling, you need to find the minimum black point to have your targeted blacks be actual black (#000) and raise the gamma to compensate for the raised blacks to avoid over-leveling the image. This can be somewhat of a trial-and-error process until you get a satisfying result. As a starting point, you can use the following value for ImageMagick: <code>13,100%,1.3</code> (used in the example image shown above), where 13 is the raised black point and 1.3 is the gamma adjustment value.</p><p>The command (CLI) to use with ImageMagick to batch process all images inside a folder would be:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>magick mogrify -format png -dither None -colorspace Gray -level 13,100%,1.3 *.png</span></span></code></pre></div>`,10),r(`h2`,h,[l[13]||=c(`Optimizing `,-1),n(x,{heading:`Optimizing`}),l[14]||=r(`a`,{class:`header-anchor`,href:`#optimizing`,"aria-label":`Permalink to “Optimizing”`},`​`,-1)]),l[19]||=s(`<p>You can safely and losslessly optimize images to reduce file size even more using the following command (CLI) with Pingo version 1+:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pingo -lossless -s4 path-to-folder</span></span></code></pre></div>`,2)])}var _=o(u,[[`render`,g]]);export{l as __pageData,_ as default};